def _0607ce86_group_consecutive(items):
    if len(items) == 0:
        return ()
    groups = []
    start = items[0]
    prev = items[0]
    k = 1
    while k < len(items):
        x = items[k]
        if x == prev + 1:
            prev = x
        else:
            groups.append((start, prev + 1))
            start = x
            prev = x
        k = k + 1
    groups.append((start, prev + 1))
    return tuple(groups)


def _0607ce86_find_threshold(nz_values):
    x0 = sorted(nz_values, reverse=True)
    x1 = 0
    x2 = 0
    k = 0
    while k < len(x0) - 1:
        x3 = x0[k] - x0[k + 1]
        if x3 > x1:
            x1 = x3
            x2 = (x0[k] + x0[k + 1]) / 2
        k = k + 1
    return x2


def _0607ce86_most_common_size(groups):
    x0 = {}
    k = 0
    while k < len(groups):
        x1 = groups[k][1] - groups[k][0]
        if x1 in x0:
            x0[x1] = x0[x1] + 1
        else:
            x0[x1] = 1
        k = k + 1
    x2 = 0
    x3 = 0
    for s in x0:
        if x0[s] > x3:
            x3 = x0[s]
            x2 = s
    return x2


def verify_0607ce86(I: Grid) -> Grid:
    x0 = height(I)
    x1 = width(I)
    # Count non-zero cells per column
    x2 = []
    c = 0
    while c < x1:
        x3 = 0
        r = 0
        while r < x0:
            if I[r][c] != 0:
                x3 = x3 + 1
            r = r + 1
        x2.append(x3)
        c = c + 1
    # Count non-zero cells per row
    x4 = []
    r = 0
    while r < x0:
        x5 = 0
        c = 0
        while c < x1:
            if I[r][c] != 0:
                x5 = x5 + 1
            c = c + 1
        x4.append(x5)
        r = r + 1
    # Find thresholds via largest gap in sorted non-zero counts
    x6 = _0607ce86_find_threshold(x2)
    x7 = _0607ce86_find_threshold(x4)
    # Identify content columns and rows
    x8 = tuple(c for c in range(x1) if x2[c] > x6)
    x9 = tuple(r for r in range(x0) if x4[r] > x7)
    # Group consecutive content columns and rows
    x10 = _0607ce86_group_consecutive(x8)
    x11 = _0607ce86_group_consecutive(x9)
    # Keep only groups matching the most common size (the tile size)
    x12 = _0607ce86_most_common_size(x10)
    x13 = _0607ce86_most_common_size(x11)
    x14 = tuple(g for g in x10 if g[1] - g[0] == x12)
    x15 = tuple(g for g in x11 if g[1] - g[0] == x13)
    # Extract tiles and compute majority vote per cell
    x16 = []
    tr = 0
    while tr < x13:
        x17 = []
        tc = 0
        while tc < x12:
            x18 = {}
            gi = 0
            while gi < len(x15):
                gj = 0
                while gj < len(x14):
                    x19 = I[x15[gi][0] + tr][x14[gj][0] + tc]
                    if x19 in x18:
                        x18[x19] = x18[x19] + 1
                    else:
                        x18[x19] = 1
                    gj = gj + 1
                gi = gi + 1
            # Find most common value
            x20 = 0
            x21 = 0
            for v in x18:
                if x18[v] > x21:
                    x21 = x18[v]
                    x20 = v
            x17.append(x20)
            tc = tc + 1
        x16.append(tuple(x17))
        tr = tr + 1
    x22 = tuple(x16)
    # Build output grid
    x23 = []
    r = 0
    while r < x0:
        x24 = [0] * x1
        gi = 0
        while gi < len(x15):
            if x15[gi][0] <= r < x15[gi][1]:
                x25 = r - x15[gi][0]
                gj = 0
                while gj < len(x14):
                    dc = 0
                    while dc < x12:
                        x24[x14[gj][0] + dc] = x22[x25][dc]
                        dc = dc + 1
                    gj = gj + 1
                break
            gi = gi + 1
        x23.append(tuple(x24))
        r = r + 1
    return tuple(x23)


