def verify_070dd51e(I: Grid) -> Grid:
    # Get all foreground color groups (each color -> one object)
    x0 = fgpartition(I)
    # Separate into horizontal pairs (same row) and vertical pairs (same column)
    x1 = fork(equality, uppermost, lowermost)  # predicate: is horizontal
    x2 = sfilter(x0, x1)  # horizontal pairs
    x3 = difference(x0, x2)  # vertical pairs
    # For each color group, get color and the two endpoint indices, then connect
    # Build recolored connected lines for horizontal pairs
    x4 = fork(recolor, color, fork(connect, ulcorner, lrcorner))
    # Draw horizontal lines first (underpaint to not overwrite existing)
    x5 = mapply(x4, x2)  # all horizontal line cells as one object
    x6 = paint(I, x5)  # paint horizontal lines
    # Draw vertical lines on top
    x7 = mapply(x4, x3)  # all vertical line cells as one object
    x8 = paint(x6, x7)  # paint vertical lines (overwrites horizontal at intersections)
    return x8


