        # i.e., cells continuing in the same direction past 0
        # Find all 2-cell positions
        x22 = toindices(x10)  # positions of all 2 cells
        # Cells between 5 and 0 (inclusive of neighbors, exclusive of 5 and 0)
        # A cell is "between" if it's on the same line and between 5 and 0
        # A cell is "tail" if it's on the same line and past 0 (away from 5)
        # For the tail: cells where (pos - 0_pos) is in the same direction as (0_pos - 5_pos)
        # i.e., (pos - 0_pos) dot (direction) > 0
        # Since direction is axis-aligned, we can just check the relevant coordinate
        x23 = toindices(x10)
