        x38 = astuple(x20, x19)   # one perpendicular (swap and keep signs)
        x39 = astuple(invert(x20), invert(x19))  # other perpendicular (swap and negate)
        # Distance to grid edge in each perpendicular direction
        # For direction (dr, dc) from position (r0, c0):
        # If dr > 0: distance = height - 1 - r0
        # If dr < 0: distance = r0
        # If dr == 0, dc > 0: distance = width - 1 - c0
        # If dr == 0, dc < 0: distance = c0
        x40 = first(x38)  # dr1
