def _30f42897_perim_dist(x0, x1, x2, x3):
    # Compute clockwise perimeter distance from (0,0) for cell (x0, x1)
    # x2 = H, x3 = W
    # Top edge: r==0 -> dist = c
    # Right edge: c==W-1, r>0 -> dist = W + r - 1
    # Bottom edge: r==H-1, c<W-1 -> dist = 2W + H - 3 - c
    # Left edge: c==0, 0<r<H-1 -> dist = 2W + 2H - 4 - r
    x4 = equality(x0, ZERO)
    if x4:
        return x1
    x5 = decrement(x3)
    x6 = equality(x1, x5)
    if x6:
        return subtract(add(x3, x0), ONE)
    x7 = decrement(x2)
    x8 = equality(x0, x7)
    if x8:
        return subtract(subtract(add(multiply(TWO, x3), x2), THREE), x1)
    return subtract(subtract(add(multiply(TWO, x3), multiply(TWO, x2)), FOUR), x0)


def _30f42897_perim_cell(x0, x1, x2):
    # Convert perimeter distance x0 back to (r, c)
    # x1 = H, x2 = W
    # if d < W: (0, d)
    # elif d < W+H-1: (d-W+1, W-1)
    # elif d < 2W+H-2: (H-1, 2W+H-3-d)
    # else: (2W+2H-4-d, 0)
    x3 = greater(x2, x0)
    if x3:
        return astuple(ZERO, x0)
    x4 = subtract(add(x2, x1), ONE)
    x5 = greater(x4, x0)
    if x5:
        return astuple(subtract(add(x0, ONE), x2), decrement(x2))
    x6 = subtract(add(multiply(TWO, x2), x1), TWO)
    x7 = greater(x6, x0)
    if x7:
        return astuple(decrement(x1), subtract(subtract(add(multiply(TWO, x2), x1), THREE), x0))
    return astuple(subtract(subtract(add(multiply(TWO, x2), multiply(TWO, x1)), FOUR), x0), ZERO)


