def _3d588dc9_body_and_tail(comp):
    # A 14-cell 0-component consists of a 4x3 (or 3x4) body rectangle
    # plus a 2-cell tail extension from the center of one edge.
    # Determine body indices and tail indices.
    x0 = toindices(comp)
    x1 = uppermost(x0)
    x2 = lowermost(x0)
    x3 = leftmost(x0)
    x4 = rightmost(x0)
    x5 = subtract(x2, x1)  # bbox height - 1
    x6 = subtract(x4, x3)  # bbox width - 1
    # bbox is either 6x3 (height=5, width=2) or 3x6 (height=2, width=5)
    if equality(x5, FIVE):
        # 6 rows x 3 cols. Tail is 2 cells extending vertically.
        # Body is 4 rows x 3 cols.
        # Check if tail is at top or bottom.
        # Count cells in top 2 rows vs bottom 2 rows
        x7 = astuple(x1, x3)  # upper-left corner
        x8 = astuple(increment(x1), x3)
        x9 = add(x1, TWO)
        x10 = astuple(x9, x3)
        # Check if top-left 2x3 block has full cells or not
        # Tail at top: rows x1, x1+1 have only center column
        # Tail at bottom: rows x2-1, x2 have only center column
        x11 = matcher(first, x1)
        x12 = sfilter(x0, x11)
        x13 = size(x12)
        if equality(x13, ONE):
            # top row has 1 cell -> tail at top
            # tail = rows x1, x1+1, col = center col
            # body = rows x1+2 to x2, cols x3 to x4
            x14 = add(x1, TWO)
            x15 = increment(x2)
            x16 = increment(x4)
            x17 = product(interval(x14, x15, ONE), interval(x3, x16, ONE))
            x18 = difference(x0, x17)
            return (x17, x18)
        else:
            # bottom row has 1 cell -> tail at bottom
            # body = rows x1 to x2-2 (4 rows), cols x3 to x4
            x14 = subtract(x2, ONE)  # x2 - 1
            x16 = increment(x4)
            x17 = product(interval(x1, x14, ONE), interval(x3, x16, ONE))
            x18 = difference(x0, x17)
            return (x17, x18)
    else:
        # 3 rows x 6 cols. Tail is 2 cells extending horizontally.
        # Body is 3 rows x 4 cols.
        # Check if tail is at left or right.
        x11 = matcher(last, x3)
        x12 = sfilter(x0, x11)
        x13 = size(x12)
        if equality(x13, ONE):
            # left col has 1 cell -> tail at left
            x14 = add(x3, TWO)
            x15 = increment(x2)
            x16 = increment(x4)
            x17 = product(interval(x1, x15, ONE), interval(x14, x16, ONE))
            x18 = difference(x0, x17)
            return (x17, x18)
        else:
            # right col has 1 cell -> tail at right
            x14 = subtract(x4, ONE)
            x15 = increment(x2)
            x17 = product(interval(x1, x15, ONE), interval(x3, x14, ONE))
            x18 = difference(x0, x17)
            return (x17, x18)


