    x8 = sfilter(x0, compose(matcher(first, x1), identity))  # main color cells
    x9 = toindices(x8)
    x10 = intersection(x7, x9)  # main-color neighbors of inner cell
    x11 = totuple(x10)
    x12 = first(x11)
    x13 = last(x11)
    x14 = add(x12, subtract(x13, x5))  # corner = neighbor1 + (neighbor2 - inner)
    return x14


