def _626c0bcc_solve(x0):
    """Tile a set of cells into 2x2 squares and L-shapes via backtracking.
    x0: frozenset of (row, col) tuples (the 8-cells)
    Returns dict mapping (row, col) -> color.
    Color 1 = 2x2 square
    Color 2 = L missing top-left
    Color 3 = L missing bottom-left
    Color 4 = L missing top-right
    Color 5 = L missing bottom-right
    """
    # Build all possible placements
    x1 = ()  # placements as tuple of (frozenset_of_cells, color)
    x2 = set()  # possible block anchors
    x3 = totuple(x0)
    x4 = 0
    while x4 < len(x3):
        x5 = x3[x4]
        x6 = first(x5)  # row
        x7 = last(x5)   # col
        x8 = 0
        while x8 < 2:
            x9 = 0
            while x9 < 2:
                x2.add((x6 - x8, x7 - x9))
                x9 = x9 + 1
            x8 = x8 + 1
        x4 = x4 + 1

    x10 = tuple(x2)
    x11 = 0
    while x11 < len(x10):
        x12 = x10[x11]
        x13 = x12[0]  # br
        x14 = x12[1]  # bc
        x15 = ((x13, x14), (x13, x14 + 1), (x13 + 1, x14), (x13 + 1, x14 + 1))
        x16 = frozenset(x17 for x17 in x15 if x17 in x0)
        x18 = len(x16)

        if x18 == 4:
            x1 = x1 + ((x16, 1),)
            # Also generate L-shapes by skipping one cell
            x19 = totuple(x16)
            x20 = 0
            while x20 < 4:
                x21 = x19[x20]
                x22 = x16 - frozenset({x21})
                x23 = x21[0]
                x24 = x21[1]
                if x23 == x13 and x24 == x14:
                    x25 = 2
                elif x23 == x13 and x24 == x14 + 1:
                    x25 = 4
                elif x23 == x13 + 1 and x24 == x14:
                    x25 = 3
                else:
                    x25 = 5
                x1 = x1 + ((x22, x25),)
                x20 = x20 + 1
        elif x18 == 3:
            x26 = frozenset(x15) - x16
            x27 = totuple(x26)
            x28 = x27[0]
            x29 = x28[0]
            x30 = x28[1]
            if x29 == x13 and x30 == x14:
                x31 = 2
            elif x29 == x13 and x30 == x14 + 1:
                x31 = 4
            elif x29 == x13 + 1 and x30 == x14:
                x31 = 3
            else:
                x31 = 5
            x1 = x1 + ((x16, x31),)

        x11 = x11 + 1

    # Remove duplicates
    x32 = set()
    x33 = ()
    x34 = 0
    while x34 < len(x1):
        x35 = x1[x34]
        x36 = (x35[0], x35[1])
        if x36 not in x32:
            x32.add(x36)
            x33 = x33 + (x35,)
        x34 = x34 + 1
    x1 = x33

    # Backtracking solve
    x37 = {}  # result: cell -> color

    def _solve(x38):
        # x38: frozenset of remaining cells
        if len(x38) == 0:
            return True
        x39 = min(x38)
        x40 = 0
        while x40 < len(x1):
            x41 = x1[x40]
            x42 = x41[0]  # cells
            x43 = x41[1]  # color
            if x39 in x42 and x42.issubset(x38):
                x44 = totuple(x42)
                x45 = 0
                while x45 < len(x44):
                    x37[x44[x45]] = x43
                    x45 = x45 + 1
                if _solve(x38 - x42):
                    return True
                x45 = 0
                while x45 < len(x44):
                    del x37[x44[x45]]
                    x45 = x45 + 1
            x40 = x40 + 1
        return False

    _solve(x0)
    return x37


