def _7e2bad24_trace(grid, sr, sc, dr, dc, red_cells, all_indices):
    """Trace a ray from (sr,sc) in direction (dr,dc), reflecting off red barriers."""
    x0 = grid
    x1 = sr
    x2 = sc
    x3 = dr
    x4 = dc
    while True:
        x5 = add(x1, x3)  # next row
        x6 = add(x2, x4)  # next col
        x7 = astuple(x5, x6)
        # Check if next position is in grid
        x8 = contained(x7, all_indices)
        if not x8:
            break
        # Check if next position is on red barrier
        x9 = contained(x7, red_cells)
        if x9:
            # Determine barrier orientation by checking red neighbors
            x10 = astuple(x5, add(x6, ONE))
            x11 = astuple(x5, subtract(x6, ONE))
            x12 = astuple(add(x5, ONE), x6)
            x13 = astuple(subtract(x5, ONE), x6)
            x14 = either(contained(x10, red_cells), contained(x11, red_cells))  # horiz neighbors = horizontal barrier
            x15 = either(contained(x12, red_cells), contained(x13, red_cells))  # vert neighbors = vertical barrier
            # Reflect: horizontal barrier reverses row, vertical reverses col
            x3 = branch(x14, invert(x3), x3)
            x4 = branch(x15, invert(x4), x4)
            # Don't enter the red cell; the next iteration will try the new direction
        else:
            # Place blue and advance
            x0 = fill(x0, ONE, frozenset({x7}))
            x1 = x5
            x2 = x6
    return x0


