    # Marker row < frame center row => top, else bottom
    # Marker col < frame center col => left, else right
    x14 = first(x12)
    x15 = last(x12)
    x16 = first(x13)
    x17 = last(x13)
    # For marker x8: top-left if row<center and col<center
    # top quadrant rows, bottom quadrant rows
    x18 = uppermost(x1)
    x19 = lowermost(x1)
    x20 = leftmost(x1)
    x21 = rightmost(x1)
    # Split interior into quadrants
    # TL: rows [x18, x5), cols [x20, x6)
    # TR: rows [x18, x5), cols [x6, x21]
    # BL: rows [x5, x19], cols [x20, x6)
    # BR: rows [x5, x19], cols [x6, x21]
    x22 = greater(x5, x14)
    x23 = greater(x6, x15)
    # x22=True means marker row < center row => top
    # x23=True means marker col < center col => left
    # Determine color for TL quadrant based on marker positions
    # Marker x8 is at corner determined by (x22, x23)
    # If marker is top-left, its color goes in TL and BR
    # If marker is top-right, its color goes in TR and BL
    # etc.
    # TL color = marker whose position is top-left, or diagonal from bottom-right
    # Actually: the color in the quadrant nearest to the marker
    # For each quadrant, find which marker is closer
    # Simpler: determine which "corner region" each marker is in
    # marker x8: top if x22, left if x23
    # If top-left: TL=x10, BR=x10, TR=x11, BL=x11
    # If top-right: TR=x10, BL=x10, TL=x11, BR=x11
    # If bottom-left: BL=x10, TR=x10, TL=x11, BR=x11
    # If bottom-right: BR=x10, TL=x10, TR=x11, BL=x11
    # So: TL gets the color of whichever marker is top-left or bottom-right
    # TL same diagonal as BR. TR same diagonal as BL.
