    # x22=bot, x23=left: F,T => BL diagonal => x24=False
    # So if x24=True, marker x8 is on TL-BR diagonal => TL gets x10
    # If x24=False, marker x8 is on TR-BL diagonal => TL gets x11
    x25 = branch(x24, x10, x11)
