def _a64e4611_find_vband(I, bg, h, w):
    col_run_starts = {}
    c = 0
    while c < w:
        start = h
        r = h - 1
        while r >= 0:
            if I[r][c] == bg:
                start = r
            else:
                break
            r = r - 1
        col_run_starts[c] = start
        c = c + 1
    best_band = None
    best_score = 0
    spi = 0
    while spi <= h // 2:
        eligible = tuple(c for c in range(w) if col_run_starts[c] <= spi)
        if len(eligible) >= 3:
            ranges = []
            cs = eligible[0]
            ce = eligible[0]
            k = 1
            while k < len(eligible):
                if eligible[k] == ce + 1:
                    ce = eligible[k]
                else:
                    ranges.append((cs, ce))
                    cs = eligible[k]
                    ce = eligible[k]
                k = k + 1
            ranges.append((cs, ce))
            ri = 0
            while ri < len(ranges):
                rcs, rce = ranges[ri]
                bw = rce - rcs + 1
                if bw >= 3:
                    actual_spi = max(col_run_starts[c] for c in range(rcs, rce + 1))
                    score = bw * (h - actual_spi)
                    if score > best_score:
                        best_score = score
                        best_band = (rcs, rce, actual_spi)
                ri = ri + 1
        spi = spi + 1
    return best_band


def _a64e4611_contiguous(rows, min_size):
    if len(rows) == 0:
        return []
    ranges = []
    cs = rows[0]
