    k = 1
    while k < len(rows):
        if rows[k] == ce + 1:
            ce = rows[k]
        else:
            if ce - cs + 1 >= min_size:
                ranges.append((cs, ce))
            cs = rows[k]
            ce = rows[k]
        k = k + 1
    if ce - cs + 1 >= min_size:
        ranges.append((cs, ce))
    return ranges


